import{_ as a,o as t,c as r,a3 as o}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"42. Travel Payment","description":"","frontmatter":{"title":"42. Travel Payment","eba":"Allied Health Professionals 2021-2026","topics":["hours","overtime","allowances","travel"]},"headers":[],"relativePath":"ebas/allied-health/allowances/42-travel-payment.md","filePath":"ebas/allied-health/allowances/42-travel-payment.md"}'),l={name:"ebas/allied-health/allowances/42-travel-payment.md"};function n(i,e,s,m,p,d){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="_42-travel-payment" tabindex="-1">42. Travel Payment <a class="header-anchor" href="#_42-travel-payment" aria-label="Permalink to &quot;42. Travel Payment&quot;">​</a></h1><p><strong>42.1</strong> Where an Employee is required to travel on Employer business, or undertake travel that attracts the working away from home allowance in <a href="/eba/ebas/allied-health/allowances/43-working-away-from-home.html">clause 43</a> (Working Away From Home), the time spent travelling will be treated as time worked and paid as:</p><p><strong>(a)</strong> ordinary time (where travel is during ordinary hours); and/or</p><p><strong>(b)</strong> overtime (where travel is outside ordinary hours); in accordance with this Agreement.</p><p>Example 1: An Employee works from 9am to 5pm at work site A. Just before 5pm the Employee is directed to travel to site B to perform overtime until 7pm and such a direction is reasonable. The Employee arrives at site B at 5:30pm to commence work. The Employee will be entitled to payment at the applicable overtime rates for 30 minutes of travel.</p><p>Example 2:</p><p>An Employee is required to work at a location that requires an overnight stay and will be paid the working away from home allowance. The Employee travels to the location during the Employee’s ordinary hours. The time spent travelling is paid at ordinary rates. Travelling and Relo cation</p>',7)])])}const y=a(l,[["render",n]]);export{c as __pageData,y as default};
